                        <input type="number" value={classNum} onChange={e => setClassNum(e.target.value)} placeholder="반" className="p-2 border rounded text-center" />
                        <input type="number" value={number} onChange={e => setNumber(e.target.value)} placeholder="번호" className="p-2 border rounded text-center" />
                    </div>
                </div>
                <button onClick={handleSubmit} disabled={loading} className="w-full mt-4 p-3 bg-blue-600 text-white font-bold rounded-lg disabled:bg-gray-400">
