                                    <button onClick={() => handleDelete(tax.id)} className="block text-xs text-gray-400 hover:text-red-500 mt-1 ml-auto">삭제</button>
                                </div>
                            </div>
                            <div className="mb-2">
                                <div className="flex justify-between text-xs text-gray-600 mb-1">
                                    <span>납부 현황</span>
                                    <span>{paidCount} / {totalCount}명 ({progress.toFixed(0)}%)</span>
                                </div>
                                <div className="w-full bg-gray-200 rounded-full h-2.5">
                                    <div className="bg-blue-600 h-2.5 rounded-full" style={{ width: `${progress}%` }}></div>
                                </div>
                            </div>
                            <div className="text-xs text-gray-500 mt-2">
                                미납자: {tax.recipients.filter(r => !r.isPaid).map(r => {
