const StudentManagementView: React.FC<{ students: (User & { account: Account | null })[], refresh: () => void }> = ({ students, refresh }) => {
    const [showAddModal, setShowAddModal] = useState(false);
    const [selectedIds, setSelectedIds] = useState<string[]>([]);
    const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

    const handleDelete = async () => {
        if (selectedIds.length === 0) return;
        if (!confirm(`${selectedIds.length}명의 학생을 삭제하시겠습니까?`)) return;

        try {
            const result = await api.deleteStudents(selectedIds);
            setMessage({ type: 'success', text: result });
            setSelectedIds([]);
            refresh();
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message });
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">학생 관리</h2>
                <div className="space-x-2">
                    {selectedIds.length > 0 && (
                        <button onClick={handleDelete} className="px-3 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700">
                            삭제 ({selectedIds.length})
                        </button>
                    )}
                    <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 flex items-center inline-flex">
                        <PlusIcon className="w-5 h-5 mr-1" /> 학생 추가
                    </button>
                </div>
            </div>

            <div className="bg-white rounded-xl shadow-sm overflow-hidden">
                <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 text-gray-500">
                        <tr>
                            <th className="p-3 w-10"><input type="checkbox" onChange={e => setSelectedIds(e.target.checked ? students.map(s => s.userId) : [])} checked={selectedIds.length === students.length && students.length > 0} /></th>
                            <th className="p-3">번호</th>
                            <th className="p-3">이름</th>
                            <th className="p-3">자산</th>
                            <th className="p-3">QR 토큰</th>
                        </tr>
                    </thead>
                    <tbody>
                        {students.map(s => (
                            <tr key={s.userId} className="border-t hover:bg-gray-50">
                                <td className="p-3"><input type="checkbox" checked={selectedIds.includes(s.userId)} onChange={e => {
                                    if(e.target.checked) setSelectedIds([...selectedIds, s.userId]);
                                    else setSelectedIds(selectedIds.filter(id => id !== s.userId));
                                }} /></td>
                                <td className="p-3 text-gray-600">{s.grade}-{s.class} {s.number}</td>
                                <td className="p-3 font-medium">{s.name}</td>
                                <td className="p-3 text-blue-600 font-bold">{s.account?.balance.toLocaleString()}권</td>
                                <td className="p-3 font-mono text-xs text-gray-400 truncate max-w-[100px]">{s.account?.qrToken || '-'}</td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {showAddModal && <AddStudentModal onClose={() => setShowAddModal(false)} onComplete={refresh} />}
            {message && <MessageModal isOpen={!!message} type={message.type} message={message.text} onClose={() => setMessage(null)} />}
        </div>
    );
};

const JobManagementView: React.FC<{ refresh: () => void }> = ({ refresh }) => {
    const [jobs, setJobs] = useState<Job[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const [message, setMessage] = useState<{type: 'success'|'error', text: string} | null>(null);

    const fetchJobs = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getJobs();
            setJobs(data);
        } catch (e) { console.error(e); }
        finally { setLoading(false); }
    }, []);

    useEffect(() => { fetchJobs(); }, [fetchJobs]);

    const handleDelete = async (jobId: string) => {
        if(!confirm('삭제하시겠습니까?')) return;
        try {
            await api.deleteJob(jobId);
            fetchJobs();
        } catch(e: any) { setMessage({type: 'error', text: e.message}); }
