    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">직업 관리</h2>
                <div className="space-x-2">
                    <button onClick={handlePayAll} className="px-3 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700">
                        전체 월급 지급
                    </button>
                    <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
                        직업 추가
                    </button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {jobs.map(job => (
                    <div key={job.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 relative">
                        <button onClick={() => handleDelete(job.id)} className="absolute top-2 right-2 text-gray-400 hover:text-red-500"><XIcon className="w-5 h-5"/></button>
                        <h3 className="font-bold text-lg mb-1">{job.jobName}</h3>
                        <p className="text-sm text-gray-500 mb-3 h-10 line-clamp-2">{job.description}</p>
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-sm text-gray-600">월급</span>
                            <span className="font-bold text-blue-600">{job.salary.toLocaleString()}권</span>
