            {showAddModal && <AddJobModal onClose={() => setShowAddModal(false)} onComplete={fetchJobs} />}
            {message && <MessageModal isOpen={!!message} type={message.type} message={message.text} onClose={() => setMessage(null)} />}
        </div>
