const TaxView: React.FC<{ students: (User & { account: Account | null })[] }> = ({ students }) => {
    const [taxes, setTaxes] = useState<TaxItemWithRecipients[]>([]);
    const [showAddModal, setShowAddModal] = useState(false);
    const [loading, setLoading] = useState(true);
    const [expandedTaxId, setExpandedTaxId] = useState<string | null>(null);

    const fetchTaxes = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getTaxes();
            setTaxes(data);
        } catch(e) { console.error(e); }
        finally { setLoading(false); }
    }, []);

    useEffect(() => { fetchTaxes(); }, [fetchTaxes]);

    const handleDelete = async (id: string) => {
        if(!confirm('삭제하시겠습니까?')) return;
        try {
            await api.deleteTax(id);
            fetchTaxes();
        } catch(e: any) { alert(e.message); }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">세금 관리</h2>
                <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700">
                    세금 고지
                </button>
            </div>

            <div className="space-y-4">
                {taxes.map(tax => {
                    const paidRecipients = tax.recipients.filter(r => r.isPaid);
                    const unpaidRecipients = tax.recipients.filter(r => !r.isPaid);
                    const totalCount = tax.recipients.length;
                    const progress = totalCount > 0 ? (paidRecipients.length / totalCount) * 100 : 0;
                    const isExpanded = expandedTaxId === tax.id;

                    const getName = (userId: string) => {
                        const s = students.find(st => st.userId === userId);
                        return s ? s.name : 'Unknown';
                    };

                    return (
                        <div key={tax.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 transition-all">
                            <div className="flex justify-between items-start mb-3">
                                <div>
                                    <h3 className="font-bold text-lg text-gray-800">{tax.name}</h3>
                                    <p className="text-sm text-gray-500">납부 기한: {new Date(tax.dueDate).toLocaleDateString()}</p>
                                </div>
                                <div className="text-right">
                                    <span className="font-bold text-red-600 text-lg block">{tax.amount.toLocaleString()}권</span>
                                    <button onClick={(e) => { e.stopPropagation(); handleDelete(tax.id); }} className="text-xs text-gray-400 hover:text-red-500 mt-1 underline">삭제</button>
                                </div>
                            </div>

                            <div 
                                className="mb-2 cursor-pointer group" 
                                onClick={() => setExpandedTaxId(isExpanded ? null : tax.id)}
                            >
                                <div className="flex justify-between text-xs text-gray-600 mb-1">
                                    <span className="font-bold flex items-center hover:text-blue-600 transition-colors">
                                        납부 현황 {isExpanded ? '▲' : '▼'}
                                    </span>
                                    <span className="font-mono">{paidRecipients.length} / {totalCount}명 ({progress.toFixed(0)}%)</span>
                                </div>
                                <div className="w-full bg-gray-200 rounded-full h-3 overflow-hidden">
                                    <div className="bg-blue-600 h-full rounded-full transition-all duration-500" style={{ width: `${progress}%` }}></div>
                                </div>
                            </div>

                            {isExpanded ? (
                                <div className="mt-4 pt-4 border-t grid grid-cols-2 gap-4 animate-fadeIn">
                                    <div className="bg-green-50 p-3 rounded-lg border border-green-100">
                                        <h4 className="font-bold text-green-700 text-sm mb-2 flex items-center">
                                            <CheckIcon className="w-4 h-4 mr-1"/> 납부 완료 ({paidRecipients.length})
                                        </h4>
                                        <div className="flex flex-wrap gap-1 max-h-40 overflow-y-auto">
                                            {paidRecipients.length > 0 ? paidRecipients.map(r => (
                                                <span key={r.id} className="px-2 py-1 bg-white border border-green-200 text-green-700 text-xs rounded shadow-sm">
                                                    {getName(r.studentUserId)}
                                                </span>
                                            )) : <span className="text-xs text-gray-400 w-full text-center py-2">없음</span>}
                                        </div>
                                    </div>

                                    <div className="bg-red-50 p-3 rounded-lg border border-red-100">
                                        <h4 className="font-bold text-red-700 text-sm mb-2 flex items-center">
                                            <ErrorIcon className="w-4 h-4 mr-1"/> 미납 ({unpaidRecipients.length})
                                        </h4>
                                        <div className="flex flex-wrap gap-1 max-h-40 overflow-y-auto">
                                            {unpaidRecipients.length > 0 ? unpaidRecipients.map(r => (
                                                <span key={r.id} className="px-2 py-1 bg-white border border-red-200 text-red-700 text-xs rounded shadow-sm">
                                                    {getName(r.studentUserId)}
                                                </span>
                                            )) : <span className="text-xs text-gray-400 w-full text-center py-2">없음</span>}
                                        </div>
                                    </div>
                                </div>
                            ) : (
                                unpaidRecipients.length > 0 && (
                                    <div className="text-xs text-gray-400 mt-2 truncate">
                                        미납: {unpaidRecipients.map(r => getName(r.studentUserId)).join(', ')}
                                    </div>
                                )
                            )}
                        </div>
                    );
                })}
            </div>

            {showAddModal && <AddTaxModal students={students} onClose={() => setShowAddModal(false)} onComplete={fetchTaxes} />}
        </div>
    );
};

const FundManagementView: React.FC<{ students: (User & { account: Account | null })[] }> = ({ students }) => {
    const [funds, setFunds] = useState<Fund[]>([]);
    const [loading, setLoading] = useState(true);
    const [showAddModal, setShowAddModal] = useState(false);
    const [messageModal, setMessageModal] = useState<{isOpen: boolean, type: 'success'|'error', message: string}>({isOpen: false, type: 'success', message: ''});
    const [settleModal, setSettleModal] = useState<{ isOpen: boolean, fund: Fund | null }>({ isOpen: false, fund: null });

    const fetchFunds = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getFunds();
            setFunds(data);
        } catch (error) {
            console.error("Failed to fetch funds", error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchFunds();
    }, [fetchFunds]);

    const handleSettle = async (status: FundStatus) => {
        if (!settleModal.fund) return;
        try {
            const resultMsg = await api.settleFund(settleModal.fund.id, status);
            setMessageModal({ isOpen: true, type: 'success', message: resultMsg });
            setSettleModal({ isOpen: false, fund: null });
            fetchFunds();
        } catch (error: any) {
            setMessageModal({ isOpen: true, type: 'error', message: error.message });
        }
    };

    if (loading) return <div className="text-center p-8">펀드 정보를 불러오는 중...</div>;

    const getComputedStatus = (fund: Fund) => {
        const now = new Date();
        const recruitEnd = new Date(fund.recruitmentDeadline);
        // 날짜 비교를 위해 시간 부분 제거 (자정 기준)
        recruitEnd.setHours(23, 59, 59, 999);
        const maturity = new Date(fund.maturityDate);
        maturity.setHours(0, 0, 0, 0);

        // 이미 결과가 나온 상태면 DB 상태 우선
        if ([FundStatus.SUCCESS, FundStatus.EXCEED, FundStatus.FAIL].includes(fund.status)) {
            return fund.status;
        }

        if (now > maturity) return 'EVALUATING';
        if (now > recruitEnd) return 'ONGOING';
        return 'RECRUITING';
    }

    const getStatusBadge = (fund: Fund) => {
        const status = getComputedStatus(fund);

        switch (status) {
            case 'RECRUITING': return <span className="px-2 py-1 bg-green-100 text-green-800 rounded-full text-xs font-bold">모집중</span>;
            case 'ONGOING': return <span className="px-2 py-1 bg-blue-100 text-blue-800 rounded-full text-xs font-bold">운용중(마감)</span>;
            case 'EVALUATING': return <span className="px-2 py-1 bg-orange-100 text-orange-800 rounded-full text-xs font-bold">마감-평가중</span>;
            case FundStatus.SUCCESS: return <span className="px-2 py-1 bg-indigo-100 text-indigo-800 rounded-full text-xs font-bold">달성 완료</span>;
            case FundStatus.EXCEED: return <span className="px-2 py-1 bg-purple-100 text-purple-800 rounded-full text-xs font-bold">초과 달성</span>;
            case FundStatus.FAIL: return <span className="px-2 py-1 bg-gray-200 text-gray-600 rounded-full text-xs font-bold">실패</span>;
            default: return null;
        }
    };

    return (
        <div>
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">펀드 관리</h2>
                <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-[#3F649A] text-white text-xs font-semibold rounded-lg shadow hover:bg-[#32507b]">
                    펀드 개설
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {funds.map(fund => {
                    const computedStatus = getComputedStatus(fund);
                    return (
                        <div key={fund.id} className="bg-white rounded-xl shadow-sm overflow-hidden flex flex-col h-full border hover:border-blue-200 transition-colors">
                            <div className="p-4 flex justify-between items-start border-b">
                                <div>
                                    <h3 className="font-bold text-lg text-gray-800">{fund.name}</h3>
                                    <p className="text-xs text-gray-500 mt-1">제안: {fund.creatorName} 학생</p>
                                </div>
                                {getStatusBadge(fund)}
                            </div>
                            <div className="p-4 flex-grow space-y-2 text-sm">
                                <div className="flex justify-between">
                                    <span className="text-gray-500">모집 마감</span>
                                    <span className="font-medium">{new Date(fund.recruitmentDeadline).toLocaleDateString()}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-500">평가(종료)일</span>
                                    <span className="font-medium text-blue-600">{new Date(fund.maturityDate).toLocaleDateString()}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-500">투자 단위</span>
                                    <span className="font-medium">{fund.unitPrice.toLocaleString()}권</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-gray-500">현재 모집액</span>
                                    <span className="font-bold text-green-600">{(fund.totalInvestedAmount || 0).toLocaleString()}권</span>
                                </div>
                                <div className="mt-2 pt-2 border-t text-xs text-gray-500">
                                    <p>성공 시: {fund.baseReward.toLocaleString()}권 추가 지급</p>
                                    <p>초과 달성 시: {(fund.baseReward + fund.incentiveReward).toLocaleString()}권 추가 지급</p>
                                </div>
                            </div>

                            {/* Action Buttons: Only show when it's evaluation time (maturity passed) and not yet settled */}
                            {computedStatus === 'EVALUATING' && (
                                <div className="p-3 bg-orange-50 border-t flex gap-2">
                                    <button onClick={() => setSettleModal({ isOpen: true, fund })} className="w-full py-2 bg-orange-600 text-white font-bold rounded-lg hover:bg-orange-700 text-sm animate-pulse">
                                        평가 및 정산하기
                                    </button>
                                </div>
                            )}
                        </div>
                    );
                })}
                {funds.length === 0 && <div className="col-span-full text-center py-10 text-gray-500">개설된 펀드가 없습니다.</div>}
            </div>

            {showAddModal && <AddFundModal students={students} onClose={() => setShowAddModal(false)} onComplete={fetchFunds} />}

            {settleModal.isOpen && settleModal.fund && (
                <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
                    <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-sm">
                        <h3 className="text-xl font-bold mb-2">펀드 평가</h3>
                        <p className="text-gray-600 mb-6 text-sm">
                            '{settleModal.fund.name}' 펀드의 결과를 선택하세요.<br/>
                            선택 즉시 학생들에게 정산금이 지급됩니다.
                        </p>
                        <div className="flex flex-col gap-3">
                            <button onClick={() => handleSettle(FundStatus.SUCCESS)} className="w-full p-3 bg-blue-100 text-blue-800 font-bold rounded-lg hover:bg-blue-200 text-left px-4">
                                <span className="block text-lg">🎯 달성 (성공)</span>
                                <span className="text-xs font-normal">투자자: 원금 + 기본 보상<br/>제안자: 10% 보너스</span>
                            </button>
                            <button onClick={() => handleSettle(FundStatus.EXCEED)} className="w-full p-3 bg-purple-100 text-purple-800 font-bold rounded-lg hover:bg-purple-200 text-left px-4">
                                <span className="block text-lg">🚀 초과 달성</span>
                                <span className="text-xs font-normal">투자자: 원금 + 기본 + 인센티브<br/>제안자: 10% + 인센티브</span>
                            </button>
                             <button onClick={() => handleSettle(FundStatus.FAIL)} className="w-full p-3 bg-gray-100 text-gray-700 font-bold rounded-lg hover:bg-gray-200 text-left px-4">
                                <span className="block text-lg">😢 실패 (미달성)</span>
                                <span className="text-xs font-normal">50% 국고 귀속, 50% 원금 반환</span>
                            </button>
                        </div>
                        <button onClick={() => setSettleModal({ isOpen: false, fund: null })} className="mt-4 w-full p-2 text-gray-500 hover:text-gray-800">취소</button>
                    </div>
                </div>
            )}

            <MessageModal 
                isOpen={messageModal.isOpen}
                type={messageModal.type}
                message={messageModal.message}
                onClose={() => setMessageModal({ ...messageModal, isOpen: false })}
            />
        </div>
    );
};

const AddFundModal: React.FC<{ students: (User & { account: Account | null })[], onClose: () => void, onComplete: () => void }> = ({ students, onClose, onComplete }) => {
    const [formData, setFormData] = useState({
        name: '', description: '', creatorId: '', unitPrice: 1000, targetAmount: 100000,
        baseReward: 100, incentiveReward: 200, recruitmentDeadline: '', maturityDate: ''
    });
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({
            ...prev,
            [name]: ['unitPrice', 'targetAmount', 'baseReward', 'incentiveReward'].includes(name) ? parseInt(value) || 0 : value
        }));
    };

    const handleSubmit = async () => {
        if (Object.values(formData).some(v => v === '' || v === 0)) {
            setError('모든 항목을 입력해주세요.');
            return;
        }
        if (formData.baseReward > formData.unitPrice) {
            setError('기본 보상금액은 투자 단위 금액보다 클 수 없습니다. (원금 손실 방지)');
            return;
        }

        setLoading(true);
        setError('');
        try {
            await api.createFund(formData);
            onComplete();
            onClose();
        } catch (err: any) {
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg max-h-[90vh] overflow-y-auto">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xl font-bold">새 펀드 개설</h3>
