                                    <XAxis dataKey="createdAt" hide />
                                    <YAxis domain={['auto', 'auto']} hide />
                                    <Tooltip labelFormatter={() => ''} formatter={(val: number) => [`${val}권`, '가격']} />
                                    <Line type="monotone" dataKey="price" stroke="#4F46E5" strokeWidth={2} dot={false} />
                                </LineChart>
                            </ResponsiveContainer>
