                            <div className="grid grid-cols-2 gap-3">
                                <button 
                                    onClick={() => setSelectedStock({...selectedStock, mode: 'buy'} as any)}
                                    className="py-3 bg-red-50 text-red-600 font-bold rounded-xl hover:bg-red-100"
                                >
