        if (initialView && validViews.includes(initialView as View)) {
            setView(initialView as View);
        }
    }, [initialView]);

    const showNotification = useCallback((type: 'success' | 'error', text: string) => {
        setNotification({ type, text });
        setTimeout(() => {
            setNotification(null);
        }, 2000);
    }, []);

