        if (units > 10) {
            setResult({ type: 'error', text: '최대 10좌까지만 투자할 수 있습니다.' });
            return;
        }

        setLoading(true);
        setResult(null);
        try {
            const message = await api.joinFund(userId, fund.id, units);
            setResult({ type: 'success', text: message });
            setTimeout(() => onComplete(), 1500);
        } catch (err: any) {
            setResult({ type: 'error', text: err.message });
        } finally {
            setLoading(false);
        }
    };

    const totalCost = units * fund.unitPrice;
    const expectedReward = units * fund.baseReward;

    return (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4" onClick={onClose}>
            <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-sm" onClick={e => e.stopPropagation()}>
                <h3 className="text-xl font-bold mb-2">{fund.name}</h3>
                <div className="mb-4 text-sm text-gray-600 bg-gray-50 p-3 rounded-lg max-h-32 overflow-y-auto">
                    {fund.description}
                </div>

                <div className="flex items-center justify-between mb-4">
                    <p className="font-medium text-gray-700">투자 수량 (최대 10좌)</p>
                    <div className="flex items-center gap-2">
                        <button onClick={() => setUnits(u => Math.max(1, u - 1))} className="p-1 border rounded-full"><MinusIcon className="w-5 h-5"/></button>
                        <input type="number" value={units} onChange={e => setUnits(Math.min(10, Math.max(1, parseInt(e.target.value) || 1)))} className="w-16 text-center font-bold text-lg border-b-2"/>
                        <button onClick={() => setUnits(u => Math.min(10, u + 1))} className="p-1 border rounded-full"><PlusIcon className="w-5 h-5"/></button>
