                                    <span>가입금액</span>
                                    <span className="font-bold">{s.amount.toLocaleString()}권</span>
                                </div>
                                <div className="flex justify-between text-sm text-gray-600">
                                    <span>만기일</span>
                                    <span className="text-blue-600">{new Date(s.maturityDate).toLocaleDateString()}</span>
