const JobManagementView: React.FC<{ refresh: () => void }> = ({ refresh }) => {
    const [jobs, setJobs] = useState<Job[]>([]);
    const [students, setStudents] = useState<User[]>([]);
    const [showAddModal, setShowAddModal] = useState(false);
    const [assignJob, setAssignJob] = useState<Job | null>(null);
    const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);
    const [confirmAction, setConfirmAction] = useState<{ type: 'pay_all' | 'delete' | 'pay_one', data: any } | null>(null);

    const fetchData = useCallback(async () => {
        try {
            const [j, s] = await Promise.all([api.getJobs(), api.getUsersByRole(Role.STUDENT)]);
            setJobs(j);
            setStudents(s);
        } catch (e) { console.error(e); }
    }, []);

    useEffect(() => { fetchData(); }, [fetchData]);

    const handlePaySalaries = async () => {
        try {
            const msg = await api.payAllSalaries();
            setMessage({ type: 'success', text: msg });
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message });
        } finally {
            setConfirmAction(null);
        }
    };

    const handleDeleteJob = async () => {
        if (!confirmAction || confirmAction.type !== 'delete') return;
        const jobId = confirmAction.data;
        try {
            const msg = await api.deleteJob(jobId);
            setMessage({ type: 'success', text: msg });
            fetchData();
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message });
        } finally {
            setConfirmAction(null);
        }
    };

    const handlePayOneSalary = async () => {
        if (!confirmAction || confirmAction.type !== 'pay_one') return;
        const jobId = confirmAction.data;
        try {
            const msg = await api.payJobSalary(jobId);
            setMessage({ type: 'success', text: msg });
        } catch (e: any) {
            setMessage({ type: 'error', text: e.message });
        } finally {
            setConfirmAction(null);
        }
    };

    const handleUpdateIncentive = async (jobId: string, value: string) => {
        const numValue = parseInt(value) || 0;
        try {
            await api.updateJobIncentive(jobId, numValue);
            setJobs(prev => prev.map(j => j.id === jobId ? { ...j, incentive: numValue } : j));
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="h-full flex flex-col">
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-2xl font-bold text-gray-800">직업 관리</h2>
                <div className="flex gap-2">
                    <button onClick={() => setShowAddModal(true)} className="px-3 py-2 bg-[#2B548F] text-white rounded-lg text-sm font-bold shadow hover:bg-[#234576]">+ 직업 추가</button>
                    <button onClick={() => setConfirmAction({ type: 'pay_all', data: null })} className="px-3 py-2 bg-green-600 text-white rounded-lg text-sm font-bold shadow hover:bg-green-700">월급 일괄 지급</button>
                </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 overflow-y-auto">
                {jobs.map(job => (
                    <div key={job.id} className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col">
                        <div className="flex justify-between items-start mb-2"><h3 className="font-bold text-lg">{job.jobName}</h3><button onClick={() => setConfirmAction({ type: 'delete', data: job.id })} className="text-gray-400 hover:text-red-500"><XIcon className="w-5 h-5"/></button></div>
                        <p className="text-sm text-gray-600 mb-2 flex-grow">{job.description}</p>
                        <div className="bg-gray-50 p-3 rounded-lg text-sm mb-3 space-y-2">
                            <div className="flex justify-between items-center"><span className="text-gray-500">기본 월급</span><span className="font-bold">{job.salary.toLocaleString()}권</span></div>
                            <div className="flex justify-between items-center"><span className="text-gray-500">인센티브</span><input type="number" defaultValue={job.incentive} onBlur={(e) => handleUpdateIncentive(job.id, e.target.value)} className="w-20 p-1 text-right border rounded text-xs font-bold text-blue-600 bg-white focus:ring-2 focus:ring-blue-200 outline-none" /></div>
                            <div className="border-t pt-2 flex justify-between items-center font-bold text-indigo-600"><span>총 지급액</span><span>{(job.salary + (job.incentive || 0)).toLocaleString()}권</span></div>
                        </div>
                        <div className="mt-auto">
                            <div className="text-xs text-gray-500 mb-1">담당 학생 ({job.assigned_students?.length || 0}명)</div>
                            <div className="flex flex-wrap gap-1 mb-3 min-h-[1.5rem]">{job.assigned_students?.map(s => (<span key={s.userId} className="px-2 py-1 bg-blue-50 text-blue-700 rounded text-xs">{s.name}</span>))}{(!job.assigned_students || job.assigned_students.length === 0) && <span className="text-gray-300 text-xs">배정된 학생 없음</span>}</div>
                            <div className="grid grid-cols-2 gap-2"><button onClick={() => setAssignJob(job)} className="py-2 border border-blue-200 text-blue-600 rounded-lg text-sm font-bold hover:bg-blue-50 transition-colors">학생 배정</button><button onClick={() => setConfirmAction({ type: 'pay_one', data: job.id })} className="py-2 bg-indigo-100 text-indigo-700 rounded-lg text-sm font-bold hover:bg-indigo-200 transition-colors">주급 지급</button></div>
                        </div>
                    </div>
                ))}
            </div>
            {showAddModal && <AddJobModal onClose={() => setShowAddModal(false)} onComplete={fetchData} />}
            {assignJob && <AssignJobModal job={assignJob} students={students} onClose={() => setAssignJob(null)} onComplete={fetchData} />}
            <ConfirmModal 
                isOpen={!!confirmAction}
                title={confirmAction?.type === 'delete' ? '직업 삭제' : confirmAction?.type === 'pay_all' ? '월급 일괄 지급' : '주급 지급'}
                message={confirmAction?.type === 'delete' ? '정말로 이 직업을 삭제하시겠습니까?' : confirmAction?.type === 'pay_all' ? '모든 직업의 월급(인센티브 포함)을 일괄 지급하시겠습니까?' : '해당 직업의 담당 학생들에게 주급(월급+인센티브)을 지급하시겠습니까?'}
                onConfirm={() => { if (confirmAction?.type === 'delete') handleDeleteJob(); else if (confirmAction?.type === 'pay_all') handlePaySalaries(); else if (confirmAction?.type === 'pay_one') handlePayOneSalary(); }}
                onCancel={() => setConfirmAction(null)}
                isDangerous={confirmAction?.type === 'delete'}
                confirmText={confirmAction?.type === 'delete' ? '삭제' : '지급'}
            />
            <MessageModal isOpen={!!message} type={message?.type || 'success'} message={message?.text || ''} onClose={() => setMessage(null)} />
        </div>
    );
};

