const getStockProducts = async (): Promise<StockProductWithDetails[]> => {
    const { data: tableData } = await supabase.from('stock_products').select('id, name, currentPrice, volatility');
    const { data: rpcData } = await supabase.rpc('get_stock_products_with_details');
    return (tableData || []).map((tableItem: any) => {
        const rpcItem = (rpcData || []).find((r: any) => r.id === tableItem.id);
        return { id: tableItem.id, name: tableItem.name, currentPrice: tableItem.currentPrice, volatility: tableItem.volatility || 0.01, stockAccountId: rpcItem?.stockAccountId || '', totalQuantity: rpcItem?.totalQuantity || 0, valuation: rpcItem?.valuation || 0 };
    });
};

const getStudentStocks = async (userId: string): Promise<StudentStock[]> => {
    const { data, error } = await supabase.from('student_stocks').select('*, stock_products(*)').eq('userId', userId);
    handleSupabaseError(error, 'getStudentStocks');
    return (data || []).map(ss => ({ ...ss, stock: ss.stock_products }));
};

const getStockHistory = async (stockId: string): Promise<StockHistory[]> => {
    const { data } = await supabase.from('stock_price_history').select('*').eq('stockId', stockId).order('createdAt', { ascending: true }).limit(100);
    return (data || []).map((item: any) => ({ id: item.id, stockId: item.stockId, price: item.price, createdAt: item.createdAt }));
};

const buyStock = async (userId: string, stockId: string, quantity: number): Promise<string> => {
