const FundManagementView: React.FC<{ students: any[] }> = ({ students }) => {
    const [funds, setFunds] = useState<Fund[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchFunds = useCallback(async () => {
        setLoading(true);
        try {
            const data = await api.getFunds();
            setFunds(data);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => { fetchFunds(); }, [fetchFunds]);

    const handleSettle = async (fundId: string, status: FundStatus) => {
        if (!confirm(`${status === FundStatus.SUCCESS ? '성공' : '실패'} 처리하시겠습니까?`)) return;
        try {
            await api.settleFund(fundId, status);
            fetchFunds();
        } catch (error: any) {
            alert(error.message);
        }
    };

    return (
        <div className="space-y-4">
            <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                <h2 className="text-lg font-bold text-gray-800">펀드 관리</h2>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {funds.map(fund => (
                    <div key={fund.id} className="bg-white p-5 rounded-xl shadow-sm border border-gray-100 flex flex-col">
                        <div className="flex justify-between mb-2">
                            <h3 className="font-bold text-gray-800 text-lg">{fund.name}</h3>
                            <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${
                                fund.status === FundStatus.RECRUITING ? 'bg-green-100 text-green-700' :
                                fund.status === FundStatus.ONGOING ? 'bg-blue-100 text-blue-700' :
                                fund.status === FundStatus.FAIL ? 'bg-gray-100 text-gray-700' : 'bg-indigo-100 text-indigo-700'
                            }`}>
                                {fund.status}
                            </span>
                        </div>
                        <p className="text-sm text-gray-500 mb-4 flex-grow line-clamp-2">{fund.description}</p>

                        {fund.status === FundStatus.ONGOING && (
                            <div className="flex gap-2 pt-4 border-t border-gray-50">
                                <button onClick={() => handleSettle(fund.id, FundStatus.SUCCESS)} className="flex-1 py-1.5 bg-blue-600 text-white rounded-lg text-xs font-bold shadow-sm">성공(수익금 지급)</button>
                                <button onClick={() => handleSettle(fund.id, FundStatus.FAIL)} className="flex-1 py-1.5 bg-red-600 text-white rounded-lg text-xs font-bold shadow-sm">실패(원금 손실)</button>
                            </div>
                        )}
                        <div className="mt-3 text-[10px] text-gray-400 flex justify-between">
                            <span>투자자: {fund.investorCount}명</span>
                            <span>총 투자액: {fund.totalInvestedAmount?.toLocaleString()}권</span>
                        </div>
                    </div>
                ))}
                {funds.length === 0 && <div className="col-span-full py-20 text-center text-gray-400 bg-white rounded-xl border border-dashed border-gray-300">운영 중인 펀드가 없습니다.</div>}
            </div>
        </div>
    );
};

