const getMyUnpaidTaxes = async (userId: string): Promise<any[]> => {
    const { data } = await supabase.from('tax_recipients').select('*, tax_items(*)').eq('student_user_id', userId).eq('is_paid', false);
    return (data || []).map((r: any) => ({ recipientId: r.id, taxId: r.tax_id, name: r.tax_items.name, amount: r.tax_items.amount, dueDate: r.tax_items.due_date }));
};

const payTax = async (userId: string, taxId: string): Promise<string> => {
    const { data } = await supabase.rpc('pay_tax', { p_user_id: userId, p_tax_id: taxId });
    return data;
};

const getFunds = async (): Promise<Fund[]> => {
    const { data } = await supabase.rpc('get_funds_with_stats');
    return (data || []).map((f: any) => ({ ...f, creatorId: f.creator_student_id, creatorName: f.creator_name, teacherId: f.teacher_id, unitPrice: f.unit_price, targetAmount: f.target_amount, baseReward: f.base_reward, incentiveReward: f.incentive_reward, recruitmentDeadline: f.recruitment_deadline, maturityDate: f.maturity_date, totalInvestedAmount: f.total_invested_amount || 0, investorCount: f.investor_count || 0, createdAt: f.created_at }));
};

const createFund = async (fund: any): Promise<any> => {
    const { data } = await supabase.rpc('create_fund', { p_name: fund.name, p_description: fund.description, p_creator_id: fund.creatorId, p_unit_price: fund.unitPrice, p_target_amount: fund.targetAmount, p_base_reward: fund.baseReward, p_incentive_reward: fund.incentiveReward, p_recruitment_deadline: fund.recruitmentDeadline, p_maturity_date: fund.maturityDate });
    return data;
};

const joinFund = async (userId: string, fundId: string, units: number): Promise<any> => {
    const { data } = await supabase.rpc('join_fund', { p_user_id: userId, p_fund_id: fundId, p_units: units });
    return data;
};

const settleFund = async (fundId: string, resultStatus: FundStatus): Promise<any> => {
    const { data } = await supabase.rpc('settle_fund', { p_fund_id: fundId, p_status: resultStatus });
    return data;
};

const getMyFundInvestments = async (userId: string): Promise<FundInvestment[]> => {
    const { data } = await supabase.from('fund_investments').select('*, funds(*)').eq('student_user_id', userId);
    return (data || []).map((inv: any) => ({ id: inv.id, fundId: inv.fund_id, studentUserId: inv.student_user_id, units: inv.units, investedAt: inv.invested_at, fund: inv.funds ? { ...inv.funds, unitPrice: inv.funds.unit_price, maturityDate: inv.funds.maturity_date } : undefined }));
};

