const settleFund = async (fundId: string, resultStatus: FundStatus): Promise<any> => {
    const { data } = await supabase.rpc('settle_fund', { p_fund_id: fundId, p_status: resultStatus });
    return data;
};

const getMyFundInvestments = async (userId: string): Promise<FundInvestment[]> => {
    const { data } = await supabase.from('fund_investments').select('*, funds(*)').eq('student_user_id', userId);
    return (data || []).map((inv: any) => ({ id: inv.id, fundId: inv.fund_id, studentUserId: inv.student_user_id, units: inv.units, investedAt: inv.invested_at, fund: inv.funds ? { ...inv.funds, unitPrice: inv.funds.unit_price, maturityDate: inv.funds.maturity_date } : undefined }));
};

